const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
return [{ json: {
  since: weekAgo.toISOString(),
  until: now.toISOString(),
  weekLabel: weekAgo.toISOString().slice(0,10) + ' to ' + now.toISOString().slice(0,10)
} }];

// Aggregate raw GitHub data into a compact digest for Claude.
const since = $('Calc Date Range').item.json.since;
const sinceTs = new Date(since).getTime();
const language = $('Config (edit these)').item.json.LANGUAGE;

// Inputs from the three Fetch nodes (each is an array of GitHub objects)
const commits = $('Fetch Commits').all().map(i => i.json).flat();
const pulls = $('Fetch Merged PRs').all().map(i => i.json).flat();
const issues = $('Fetch Closed Issues').all().map(i => i.json).flat();

// Keep only PRs merged within the last 7 days
const recentMerged = pulls.filter(p => p && p.merged_at && new Date(p.merged_at).getTime() >= sinceTs);
// Skip pull_request-typed issues (GitHub returns PRs as issues too)
const realIssues = issues.filter(i => i && !i.pull_request);

const commitLines = commits.slice(0, 30).map(c => {
  const msg = (c.commit && c.commit.message || '').split('\n')[0];
  const author = (c.author && c.author.login) || (c.commit && c.commit.author && c.commit.author.name) || 'unknown';
  return `- ${c.sha.slice(0,7)} ${msg} (@${author})`;
}).join('\n');

const prLines = recentMerged.slice(0, 20).map(p => {
  const labels = (p.labels || []).map(l => l.name).join(', ');
  return `- #${p.number} ${p.title} (@${p.user && p.user.login}) [${labels}]`;
}).join('\n');

const issueLines = realIssues.slice(0, 20).map(i => `- #${i.number} ${i.title} (@${i.user && i.user.login})`).join('\n');

const langInstruction = language === 'FR'
  ? 'Rédigez le résumé entièrement en français. Utilisez un ton clair et professionnel.'
  : 'Write the summary entirely in English. Use a clear, professional tone.';

const prompt = `You are a technical writer summarizing one week of activity for an open-source project.\n\n${langInstruction}\n\nRepository: ${$('Config (edit these)').item.json.GITHUB_OWNER}/${$('Config (edit these)').item.json.GITHUB_REPO}\nWeek: ${$('Calc Date Range').item.json.weekLabel}\n\nCommits (${commits.length} total, showing up to 30):\n${commitLines || '(none)'}\n\nMerged PRs (${recentMerged.length}):\n${prLines || '(none)'}\n\nClosed issues (${realIssues.length}):\n${issueLines || '(none)'}\n\nWrite a markdown summary with these sections:\n## Highlights — 3 to 5 most important changes, framed narratively (not a bullet list of commits).\n## Features Shipped — bullet list of new functionality.\n## Bug Fixes — bullet list of fixes that landed.\n## Issues Closed — short summary of closed issues.\n## Contributors — list active contributors this week.\n\nDo not invent details that are not in the data. Keep the total under 500 words.`;

return [{ json: {
  prompt,
  stats: {
    commitCount: commits.length,
    mergedPrCount: recentMerged.length,
    closedIssueCount: realIssues.length
  },
  weekLabel: $('Calc Date Range').item.json.weekLabel
} }];

const resp = $input.item.json;
const summary = (resp.content && resp.content[0] && resp.content[0].text) || '(Claude returned no text)';
const stats = $('Build Claude Prompt').item.json.stats;
const weekLabel = $('Build Claude Prompt').item.json.weekLabel;
const repo = `${$('Config (edit these)').item.json.GITHUB_OWNER}/${$('Config (edit these)').item.json.GITHUB_REPO}`;
const lang = $('Config (edit these)').item.json.LANGUAGE;

const subject = lang === 'FR'
  ? `Résumé hebdomadaire — ${repo} — ${weekLabel}`
  : `Weekly Dev Summary — ${repo} — ${weekLabel}`;

const footer = lang === 'FR'
  ? `\n\n---\nGénéré par n8n + Claude. Période : ${weekLabel}. ${stats.commitCount} commits · ${stats.mergedPrCount} PRs fusionnées · ${stats.closedIssueCount} issues clôturées.`
  : `\n\n---\nGenerated by n8n + Claude. Period: ${weekLabel}. ${stats.commitCount} commits · ${stats.mergedPrCount} merged PRs · ${stats.closedIssueCount} closed issues.`;

return [{ json: { subject, body: summary + footer } }];
